```java
class Solution {
    public int[] findIsolatedStations(int n, int[] sources, int[][] pipes) {
        // degree[i] 表示 i 号水站向外可以直接供水的管道数量
        int[] degree = new int[n];

        // 第一次遍历管道，统计每个点的出边数量，便于建立紧凑的邻接表
        for (int i = 0; i < pipes.length; i++) {
            int u = pipes[i][0];
            int v = pipes[i][1];
            int typ = pipes[i][2];

            if (typ == 0) {
                // 单向管道只产生一条从 u 到 v 的边
                degree[u]++;
            } else {
                // 双向管道等价于两条方向相反的有向边
                degree[u]++;
                degree[v]++;
            }
        }

        // graph[u] 中保存所有可以从 u 直接到达的水站
        int[][] graph = new int[n][];
        for (int i = 0; i < n; i++) {
            graph[i] = new int[degree[i]];
        }

        // pos[i] 表示当前已经向 graph[i] 中填入了多少个邻接点
        int[] pos = new int[n];

        // 第二次遍历管道，真正填充邻接表
        for (int i = 0; i < pipes.length; i++) {
            int u = pipes[i][0];
            int v = pipes[i][1];
            int typ = pipes[i][2];

            if (typ == 0) {
                // 单向管道：只允许水从 u 流向 v
                graph[u][pos[u]++] = v;
            } else {
                // 双向管道：两个方向都可以流动
                graph[u][pos[u]++] = v;
                graph[v][pos[v]++] = u;
            }
        }

        // visited[i] 表示 i 号水站是否可以获得供水
        boolean[] visited = new boolean[n];

        // 用数组模拟队列，最多只会有 n 个水站入队
        int[] queue = new int[n];
        int head = 0;
        int tail = 0;

        // 所有源头站同时作为搜索起点
        for (int i = 0; i < sources.length; i++) {
            int s = sources[i];
            if (0 <= s && s < n && !visited[s]) {
                visited[s] = true;
                queue[tail++] = s;
            }
        }

        // 广度优先搜索，沿着水流方向寻找所有可供水水站
        while (head < tail) {
            int cur = queue[head++];

            for (int i = 0; i < graph[cur].length; i++) {
                int nxt = graph[cur][i];

                if (!visited[nxt]) {
                    visited[nxt] = true;
                    queue[tail++] = nxt;
                }
            }
        }

        // 先统计孤立站数量，用于创建长度准确的结果数组
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                count++;
            }
        }

        // 按编号从小到大写入答案，因此结果天然有序
        int[] ans = new int[count];
        int idx = 0;
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                ans[idx++] = i;
            }
        }

        return ans;
    }
}
