var findIsolatedStations = function(n, sources, pipes) {
    // 构建邻接表，graph[i] 表示 i 能直接供水到的水站列表
    const graph = Array.from({ length: n }, () => []);

    for (const [u, v, typ] of pipes) {
        graph[u].push(v);
        if (typ === 1) {
            // 双向管道需要增加反向边
            graph[v].push(u);
        }
    }

    // visited[i] 表示 i 是否已获得供水
    const visited = new Array(n).fill(false);
    const queue = [];
    let head = 0;

    // 先将所有源头站入队
    for (const s of sources) {
        if (s >= 0 && s < n && !visited[s]) {
            visited[s] = true;
            queue.push(s);
        }
    }

    // BFS 搜索所有可达水站
    while (head < queue.length) {
        const cur = queue[head++];
        for (const nxt of graph[cur]) {
            if (!visited[nxt]) {
                visited[nxt] = true;
                queue.push(nxt);
            }
        }
    }

    // 收集没有水的孤立水站
    const ans = [];
    for (let i = 0; i < n; i++) {
        if (!visited[i]) {
            ans.push(i);
        }
    }

    return ans;
};
