int* findIsolatedStations(int n, int* sources, int sourcesSize, int** pipes, int pipesSize, int* returnSize) {
    // 统计每个水站的出度，用于构建邻接表
    int* degree = (int*)calloc(n, sizeof(int));
    for (int i = 0; i < pipesSize; i++) {
        int u = pipes[i][0], v = pipes[i][1], typ = pipes[i][2];
        degree[u]++;
        if (typ == 1) degree[v]++;
    }

    // 分配邻接表内存
    int** graph = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        graph[i] = (int*)malloc(degree[i] * sizeof(int));
    }

    // 填充邻接表
    int* pos = (int*)calloc(n, sizeof(int));
    for (int i = 0; i < pipesSize; i++) {
        int u = pipes[i][0], v = pipes[i][1], typ = pipes[i][2];
        graph[u][pos[u]++] = v;
        if (typ == 1) {
            graph[v][pos[v]++] = u;
        }
    }
    free(pos);

    // visited[i] 表示是否获得供水
    int* visited = (int*)calloc(n, sizeof(int));
    // 队列模拟 BFS
    int* queue = (int*)malloc(n * sizeof(int));
    int head = 0, tail = 0;

    // 源头站入队
    for (int i = 0; i < sourcesSize; i++) {
        int s = sources[i];
        if (s >= 0 && s < n && !visited[s]) {
            visited[s] = 1;
            queue[tail++] = s;
        }
    }

    // BFS 扩展供水范围
    while (head < tail) {
        int cur = queue[head++];
        for (int i = 0; i < degree[cur]; i++) {
            int nxt = graph[cur][i];
            if (!visited[nxt]) {
                visited[nxt] = 1;
                queue[tail++] = nxt;
            }
        }
    }

    // 统计孤立站数量
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) count++;
    }

    // 生成答案数组
    int* ans = (int*)malloc(count * sizeof(int));
    *returnSize = count;
    int idx = 0;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            ans[idx++] = i;
        }
    }

    // 释放内存
    for (int i = 0; i < n; i++) free(graph[i]);
    free(graph);
    free(degree);
    free(visited);
    free(queue);

    return ans;
}
